using System.Net;
using Microsoft.AspNetCore.HttpOverrides;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// FIX 1 – ValidateScopes (now on by default in dev) rejects scoped services
// resolved from the root provider inside a singleton factory.
// Changed from AddSingleton to AddScoped so the lifetime matches IUserService.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));
// FIX 2 – HttpClientFactory now uses SocketsHttpHandler by default.
// The old cast to HttpClientHandler throws InvalidCastException.
// Use ConfigurePrimaryHttpMessageHandler (also resolves the CS0618 obsoletion).
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() =>
        new SocketsHttpHandler { UseCookies = false });
// FIX 3 – Trace-level HttpClientFactory logs now redact ALL header values.
// Allowlist the specific non-sensitive headers you need for debugging.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h =>
        h != "X-Request-Id"
        && h != "X-Correlation-Id"
        && h != "Content-Type"
        && h != "Accept"));
// FIX 4 – ForwardedHeadersMiddleware now ignores X-Forwarded-* headers
// from proxies not in KnownProxies / KnownNetworks.
// Add your reverse-proxy address(es) here.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    options.KnownProxies.Add(IPAddress.Parse("127.0.0.1"));
    // TODO: replace with your actual proxy IP, e.g. IPAddress.Parse("10.0.0.1")
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

